-- ── Functions ───────────────────────────────────────────────────────
CREATE OR REPLACE FUNCTION public.create_account_with_profiles(p_supabase_user_id uuid, p_name text, p_email text, p_profiles profile_type_enum[])
 RETURNS users
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user public.users;
  v_pt   public.profile_type_enum;
  v_cols text := 'id, supabase_user_id, email';
  v_vals text;
  v_role text := CASE
    WHEN 'cargo'::public.profile_type_enum  = ANY (p_profiles)
     AND 'vessel'::public.profile_type_enum = ANY (p_profiles) THEN 'broker'
    WHEN 'cargo'::public.profile_type_enum  = ANY (p_profiles) THEN 'cargo_owner'
    ELSE 'vessel_owner'
  END;
BEGIN
  v_vals := format('%L, %L, %L', p_supabase_user_id, p_supabase_user_id, p_email);

  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_schema = 'public' AND table_name = 'users' AND column_name = 'name') THEN
    v_cols := v_cols || ', name';
    v_vals := v_vals || format(', %L', p_name);
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_schema = 'public' AND table_name = 'users' AND column_name = 'full_name') THEN
    v_cols := v_cols || ', full_name';
    v_vals := v_vals || format(', %L', p_name);
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_schema = 'public' AND table_name = 'users' AND column_name = 'role') THEN
    v_cols := v_cols || ', role';
    v_vals := v_vals || format(', %L', v_role);
  END IF;

  EXECUTE format('INSERT INTO public.users (%s) VALUES (%s) RETURNING *', v_cols, v_vals)
    INTO v_user;

  FOREACH v_pt IN ARRAY p_profiles LOOP
    INSERT INTO public.profiles (account_id, profile_type, display_name)
    VALUES (v_user.id, v_pt, p_name)
    ON CONFLICT (account_id, profile_type) DO NOTHING;
  END LOOP;

  RETURN v_user;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_app_user_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(
    (SELECT id FROM public.users WHERE supabase_user_id = auth.uid() LIMIT 1),
    (SELECT id FROM public.users WHERE id = auth.uid() LIMIT 1)
  );
$function$;

CREATE OR REPLACE FUNCTION public.fn_build_market_insights(p_from date, p_to date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
WITH params AS (
  SELECT 5::int AS floor_n,
         ARRAY['AG','R.SEA','E.MED','B.SEA','A.SEA']::public.zone_enum[] AS focus
),
-- Live cargo activity in the window, within scope. Only the coarse, non-PII
-- columns are pulled — no broker, notes, ref, laycan, ownership, or exact id use.
live_cargo AS (
  SELECT
    cl.commodity_name,
    cl.is_grain_cargo,
    cl.cargo_type,
    cl.qty_max_mt,
    cl.load_zone,
    cl.disch_zone,
    CASE
      WHEN cl.is_grain_cargo THEN 'Grain'
      WHEN cl.cargo_type = 'Break Bulk' THEN 'Break-bulk (CSS)'
      ELSE 'Dry bulk (IMSBC)'
    END AS regime,
    CASE
      WHEN cl.qty_max_mt < 10000 THEN '<10K'
      WHEN cl.qty_max_mt < 20000 THEN '10–20K'
      WHEN cl.qty_max_mt < 35000 THEN '20–35K'
      WHEN cl.qty_max_mt < 50000 THEN '35–50K'
      ELSE '50K+'
    END AS size_band
  FROM public.cargo_listings cl, params p
  WHERE cl.review_status = 'APPROVED'
    AND cl.status IN ('IN','PARTIAL')
    AND cl.created_at >= p_from::timestamptz
    AND cl.created_at <  (p_to + 1)::timestamptz
    AND cl.qty_max_mt < 66000
    AND (cl.load_zone = ANY (p.focus) OR cl.disch_zone = ANY (p.focus))
),
open_tonnage AS (
  SELECT count(*)::int AS n
  FROM public.vessel_availability va, params p
  WHERE va.review_status = 'APPROVED'
    AND va.status = 'OPEN'
    AND va.created_at >= p_from::timestamptz
    AND va.created_at <  (p_to + 1)::timestamptz
    AND (va.open_zone IS NULL OR va.open_zone = ANY (p.focus))
),
-- ── grouped counts (raw, pre-floor) ──
regime_c AS (SELECT regime AS k, count(*) c FROM live_cargo GROUP BY regime),
band_c   AS (SELECT size_band AS k, count(*) c FROM live_cargo GROUP BY size_band),
lane_c   AS (SELECT (load_zone::text || ' → ' || disch_zone::text) AS k, count(*) c,
                    mode() WITHIN GROUP (ORDER BY size_band) AS band
             FROM live_cargo WHERE load_zone IS NOT NULL AND disch_zone IS NOT NULL GROUP BY 1),
comm_c   AS (SELECT commodity_name AS k, count(*) c FROM live_cargo WHERE commodity_name IS NOT NULL GROUP BY 1),
loadz_c  AS (SELECT load_zone::text AS k, count(*) c FROM live_cargo WHERE load_zone IS NOT NULL GROUP BY 1),
dischz_c AS (SELECT disch_zone::text AS k, count(*) c FROM live_cargo WHERE disch_zone IS NOT NULL GROUP BY 1),
-- ── apply the floor: <5 in any group folds into "Other" ──
regime_f AS (
  SELECT k, c FROM regime_c, params p WHERE c >= p.floor_n
  UNION ALL SELECT 'Other', sum(c) FROM regime_c, params p WHERE c < p.floor_n HAVING sum(c) > 0
),
band_f AS (
  SELECT k, c FROM band_c, params p WHERE c >= p.floor_n
  UNION ALL SELECT 'Other', sum(c) FROM band_c, params p WHERE c < p.floor_n HAVING sum(c) > 0
),
lane_f AS (
  SELECT k, c, band FROM lane_c, params p WHERE c >= p.floor_n
  UNION ALL SELECT 'Other', sum(c), 'Mixed' FROM lane_c, params p WHERE c < p.floor_n HAVING sum(c) > 0
),
comm_f AS (
  SELECT k, c FROM comm_c, params p WHERE c >= p.floor_n
  UNION ALL SELECT 'Other', sum(c) FROM comm_c, params p WHERE c < p.floor_n HAVING sum(c) > 0
),
loadz_f AS (
  SELECT k, c FROM loadz_c, params p WHERE c >= p.floor_n
  UNION ALL SELECT 'Other', sum(c) FROM loadz_c, params p WHERE c < p.floor_n HAVING sum(c) > 0
),
dischz_f AS (
  SELECT k, c FROM dischz_c, params p WHERE c >= p.floor_n
  UNION ALL SELECT 'Other', sum(c) FROM dischz_c, params p WHERE c < p.floor_n HAVING sum(c) > 0
)
SELECT jsonb_build_object(
  'window', jsonb_build_object('from', p_from, 'to', p_to),
  'scope',  'Regional dry bulk & break-bulk, sub-66K — AG / R.Sea / E.Med / B.Sea / A.Sea',
  'snapshot', jsonb_build_object(
    'cargoes_live',  (SELECT count(*)::int FROM live_cargo),
    'open_tonnage',  (SELECT n FROM open_tonnage),
    'active_lanes',  (SELECT count(*)::int FROM lane_c),
    -- average is a population aggregate; rounded to the nearest 500 MT, and only
    -- emitted once the population clears the floor (else null).
    'avg_cargo_size_mt', (
      SELECT CASE WHEN count(*) >= (SELECT floor_n FROM params)
             THEN (round(avg(qty_max_mt) / 500.0) * 500)::int END
      FROM live_cargo)
  ),
  'regime_mix',      (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', k, 'count', c) ORDER BY (k = 'Other'), c DESC), '[]'::jsonb) FROM regime_f),
  'size_bands',      (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', k, 'count', c) ORDER BY (k = 'Other'), c DESC), '[]'::jsonb) FROM band_f),
  'top_lanes',       (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', k, 'count', c, 'band', band) ORDER BY (k = 'Other'), c DESC), '[]'::jsonb) FROM lane_f),
  'top_commodities', (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', k, 'count', c) ORDER BY (k = 'Other'), c DESC), '[]'::jsonb) FROM comm_f),
  'load_zones',      (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', k, 'count', c) ORDER BY (k = 'Other'), c DESC), '[]'::jsonb) FROM loadz_f),
  'disch_zones',     (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', k, 'count', c) ORDER BY (k = 'Other'), c DESC), '[]'::jsonb) FROM dischz_f),
  'floor', (SELECT floor_n FROM params)
);
$function$;

CREATE OR REPLACE FUNCTION public.fn_cl_port_autofill()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  p ports%ROWTYPE;
BEGIN
  -- Load port
  IF NEW.load_port_locode IS NOT NULL AND
     (OLD.load_port_locode IS DISTINCT FROM NEW.load_port_locode) THEN
    SELECT * INTO p FROM ports WHERE locode = NEW.load_port_locode;
    NEW.load_port_name := p.trade_name;
    NEW.load_zone      := p.zone;
    NEW.load_country   := p.country;
  END IF;
  -- Discharge port
  IF NEW.disch_port_locode IS NOT NULL AND
     (OLD.disch_port_locode IS DISTINCT FROM NEW.disch_port_locode) THEN
    SELECT * INTO p FROM ports WHERE locode = NEW.disch_port_locode;
    NEW.disch_port_name := p.trade_name;
    NEW.disch_zone      := p.zone;
    NEW.disch_country   := p.country;
  END IF;
  -- Auto-set DG and grain flags from commodity
  IF NEW.commodity_id IS NOT NULL AND
     (OLD.commodity_id IS DISTINCT FROM NEW.commodity_id) THEN
    SELECT is_dg, is_grain
    INTO NEW.is_dg_cargo, NEW.is_grain_cargo
    FROM commodities WHERE id = NEW.commodity_id;
  END IF;
  -- is_spot
  IF NEW.laycan_from IS NULL THEN
    NEW.is_spot := TRUE;
  ELSE
    NEW.is_spot := FALSE;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_csa_matchmaking_writeback()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  mc TEXT;
BEGIN
  SELECT matchmaking_column INTO mc
  FROM safety_questions
  WHERE question_key = NEW.question_key
    AND is_matchmaking_field = TRUE;

  IF mc IS NOT NULL THEN
    EXECUTE format(
      'UPDATE cargo_listings SET %I = $1 WHERE id = $2',
      mc
    ) USING NEW.answer_value, NEW.cargo_listing_id;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_is_admin()
 RETURNS boolean
 LANGUAGE sql
 STABLE
AS $function$
  SELECT COALESCE(
    (auth.jwt() -> 'app_metadata' ->> 'role') = 'admin',
    FALSE
  );
$function$;

CREATE OR REPLACE FUNCTION public.fn_is_org_admin(p_org_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.organization_members
    WHERE org_id = p_org_id AND user_id = public.fn_app_user_id()
      AND member_role = 'admin' AND is_current AND status = 'active'
  );
$function$;

CREATE OR REPLACE FUNCTION public.fn_lo_close_previous()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.is_current AND NEW.role = 'primary' THEN
    UPDATE listing_ownership
    SET is_current = FALSE, owned_until = NOW()
    WHERE listing_type = NEW.listing_type
      AND listing_id   = NEW.listing_id
      AND role         = 'primary'
      AND is_current   = TRUE
      AND id          != NEW.id;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_market_insights_freeze()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.published_at IS NOT NULL THEN
    IF NEW.payload    IS DISTINCT FROM OLD.payload
       OR NEW.range_from IS DISTINCT FROM OLD.range_from
       OR NEW.range_to   IS DISTINCT FROM OLD.range_to
       OR NEW.week_id    IS DISTINCT FROM OLD.week_id
       OR NEW.published_at IS DISTINCT FROM OLD.published_at THEN
      RAISE EXCEPTION 'Published edition % is frozen — only the narrative may change', OLD.week_id;
    END IF;
  END IF;
  NEW.updated_at := now();
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_market_insights_subscribe(p_email text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_email text := lower(btrim(coalesce(p_email, '')));
BEGIN
  IF v_email !~ '^[^@\s]+@[^@\s]+\.[^@\s]+$' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'invalid_email');
  END IF;
  INSERT INTO public.market_insights_subscribers (email, source)
  VALUES (v_email, 'market_insights')
  ON CONFLICT (email) DO NOTHING;
  RETURN jsonb_build_object('ok', true);
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_match_auto_cleanup()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_TABLE_NAME = 'cargo_listings' THEN
    IF NEW.status NOT IN ('IN','PARTIAL') OR NEW.review_status != 'APPROVED' THEN
      DELETE FROM matches WHERE cargo_id = NEW.id;
    END IF;
  ELSIF TG_TABLE_NAME = 'vessel_availability' THEN
    IF NEW.status != 'OPEN' OR NEW.review_status != 'APPROVED' THEN
      DELETE FROM matches WHERE vessel_avail_id = NEW.id;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_match_cleanup()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  removed INTEGER;
BEGIN
  WITH deleted AS (
    DELETE FROM matches m
    USING cargo_listings c, vessel_availability v
    WHERE m.cargo_id = c.id
      AND m.vessel_avail_id = v.id
      AND (
        c.status NOT IN ('IN','PARTIAL')
        OR v.status != 'OPEN'
        OR c.review_status != 'APPROVED'
        OR v.review_status != 'APPROVED'
      )
    RETURNING m.id
  )
  SELECT COUNT(*) INTO removed FROM deleted;
  RETURN removed;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_my_admin_org_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT org_id FROM public.organization_members
  WHERE user_id = public.fn_app_user_id() AND member_role = 'admin'
    AND is_current = TRUE AND status = 'active'
  LIMIT 1;
$function$;

CREATE OR REPLACE FUNCTION public.fn_my_membership()
 RETURNS TABLE(org_id uuid, org_name text, org_type text, member_role text, status text, requested_company_name text, added_at timestamp with time zone)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT m.org_id, o.name, o.org_type, m.member_role, m.status,
         m.requested_company_name, m.added_at
  FROM public.organization_members m
  JOIN public.organizations o ON o.id = m.org_id
  WHERE m.user_id = public.fn_app_user_id()
  ORDER BY (m.status = 'active') DESC, (m.status = 'pending') DESC, m.added_at DESC
  LIMIT 1;
$function$;

CREATE OR REPLACE FUNCTION public.fn_my_org_ids()
 RETURNS uuid[]
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(array_agg(org_id), '{}')
  FROM public.organization_members
  WHERE user_id = public.fn_app_user_id() AND is_current;
$function$;

CREATE OR REPLACE FUNCTION public.fn_oc_auto_reject_on_close()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'CLOSED' AND OLD.status != 'CLOSED' THEN
    UPDATE ownership_claims
    SET status           = 'REJECTED',
        resolution_note  = 'Auto-rejected: listing closed before claim resolved.',
        resolved_at      = NOW()
    WHERE listing_id = NEW.id
      AND listing_type = 'cargo'
      AND status IN ('PENDING','DISPUTED');
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_oc_detect_dispute()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF (SELECT COUNT(*) FROM ownership_claims
      WHERE listing_id   = NEW.listing_id
        AND listing_type = NEW.listing_type
        AND status       = 'PENDING'
        AND id          != NEW.id) > 0 THEN
    -- Mark all pending claims on this listing as DISPUTED
    UPDATE ownership_claims
    SET status = 'DISPUTED'
    WHERE listing_id   = NEW.listing_id
      AND listing_type = NEW.listing_type
      AND status       = 'PENDING';
    NEW.status := 'DISPUTED';
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_org_manage_member(p_org_id uuid, p_user_id uuid, p_action text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT (public.fn_is_admin() OR p_org_id = public.fn_my_admin_org_id()) THEN
    RAISE EXCEPTION 'Not an admin of this company';
  END IF;
  IF p_user_id = public.fn_app_user_id() AND p_action IN ('remove', 'reject', 'make_broker') THEN
    RAISE EXCEPTION 'You cannot change your own admin seat';
  END IF;

  IF p_action = 'approve' THEN
    UPDATE public.organization_members SET status = 'active', is_current = TRUE,
      decided_at = now(), decided_by = public.fn_app_user_id()
      WHERE org_id = p_org_id AND user_id = p_user_id;
  ELSIF p_action = 'reject' THEN
    UPDATE public.organization_members SET status = 'rejected', is_current = FALSE,
      decided_at = now(), decided_by = public.fn_app_user_id()
      WHERE org_id = p_org_id AND user_id = p_user_id;
  ELSIF p_action = 'remove' THEN
    DELETE FROM public.organization_members WHERE org_id = p_org_id AND user_id = p_user_id;
  ELSIF p_action = 'make_admin' THEN
    UPDATE public.organization_members SET member_role = 'admin'
      WHERE org_id = p_org_id AND user_id = p_user_id AND status = 'active';
  ELSIF p_action = 'make_broker' THEN
    UPDATE public.organization_members SET member_role = 'broker'
      WHERE org_id = p_org_id AND user_id = p_user_id AND status = 'active';
  ELSE
    RAISE EXCEPTION 'Unknown action %', p_action;
  END IF;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_org_team(p_org_id uuid)
 RETURNS TABLE(user_id uuid, full_name text, email text, member_role text, status text, added_at timestamp with time zone, requested_email_domain text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT m.user_id, u.full_name, u.email, m.member_role, m.status,
         m.added_at, m.requested_email_domain
  FROM public.organization_members m
  JOIN public.users u ON u.id = m.user_id
  WHERE m.org_id = p_org_id
    AND (public.fn_is_admin() OR p_org_id = public.fn_my_admin_org_id())
  ORDER BY (m.status = 'pending') DESC, (m.status = 'active') DESC, u.full_name;
$function$;

CREATE OR REPLACE FUNCTION public.fn_owns_cargo(p_cargo_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
      SELECT EXISTS (
        SELECT 1
        FROM public.listing_ownership lo
        WHERE lo.listing_id = p_cargo_id
          AND lo.listing_type = 'cargo'
          AND lo.is_current = true
          AND lo.role = 'primary'
          AND (
            lo.owner_user_id = auth.uid()
            OR (lo.owner_org_id IS NOT NULL AND lo.owner_org_id = ANY (public.fn_my_org_ids()))
          )
      );
    $function$;

CREATE OR REPLACE FUNCTION public.fn_owns_vessel(p_vessel_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
        SELECT EXISTS (
          SELECT 1
          FROM public.listing_ownership lo
          JOIN public.vessel_availability va ON va.id = lo.listing_id
          WHERE va.vessel_id = p_vessel_id
            AND lo.listing_type = 'vessel_availability'
            AND lo.is_current = true
            AND lo.role = 'primary'
            AND (
              lo.owner_user_id = auth.uid()
              OR (lo.owner_org_id IS NOT NULL AND lo.owner_org_id = ANY (public.fn_my_org_ids()))
            )
        );
      $function$;

CREATE OR REPLACE FUNCTION public.fn_position_checkin(p_availability_id uuid, p_eta_port_locode text DEFAULT NULL::text, p_eta_date date DEFAULT NULL::date, p_eta_time time without time zone DEFAULT NULL::time without time zone, p_open_date date DEFAULT NULL::date)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_owned boolean;
  v_now   timestamptz := now();
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.listing_ownership lo
    WHERE lo.listing_id = p_availability_id
      AND lo.listing_type = 'vessel_availability'
      AND lo.is_current = true
      AND lo.role = 'primary'
      AND (
        lo.owner_user_id = auth.uid()
        OR (lo.owner_org_id IS NOT NULL AND lo.owner_org_id = ANY (public.fn_my_org_ids()))
      )
  ) INTO v_owned;

  IF NOT (v_owned OR public.fn_is_admin()) THEN
    RAISE EXCEPTION 'Not the owner of this position';
  END IF;

  -- Confirm path: no ETA args → just stamp freshness.
  -- Update path: write the supplied fields, then stamp.
  UPDATE public.vessel_availability
  SET eta_port_locode       = COALESCE(p_eta_port_locode, eta_port_locode),
      eta_date              = COALESCE(p_eta_date, eta_date),
      eta_time              = COALESCE(p_eta_time, eta_time),
      open_date             = COALESCE(p_open_date, open_date),
      position_confirmed_at = v_now
  WHERE id = p_availability_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Position not found';
  END IF;

  RETURN v_now;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_publish_market_insights_edition(p_from date, p_to date, p_week_id text, p_publish boolean DEFAULT true)
 RETURNS market_insights_editions
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_existing public.market_insights_editions;
  v_payload  jsonb;
  v_row      public.market_insights_editions;
BEGIN
  SELECT * INTO v_existing FROM public.market_insights_editions WHERE week_id = p_week_id;

  -- Frozen: published week is returned untouched.
  IF v_existing.id IS NOT NULL AND v_existing.published_at IS NOT NULL THEN
    RETURN v_existing;
  END IF;

  v_payload := public.fn_build_market_insights(p_from, p_to);

  INSERT INTO public.market_insights_editions (week_id, range_from, range_to, payload, published_at)
  VALUES (p_week_id, p_from, p_to, v_payload, CASE WHEN p_publish THEN now() END)
  ON CONFLICT (week_id) DO UPDATE
    SET range_from = EXCLUDED.range_from,
        range_to   = EXCLUDED.range_to,
        payload    = EXCLUDED.payload,
        published_at = COALESCE(public.market_insights_editions.published_at,
                                CASE WHEN p_publish THEN now() END)
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_request_org_membership(p_org_id uuid)
 RETURNS organization_members
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
    DECLARE
      v_uid    uuid := public.fn_app_user_id();
      v_name   text;
      v_domain text;
      v_row    public.organization_members;
    BEGIN
      IF v_uid IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

      SELECT name INTO v_name FROM public.organizations WHERE id = p_org_id;
      IF v_name IS NULL THEN RAISE EXCEPTION 'Unknown company'; END IF;

      IF EXISTS (
        SELECT 1 FROM public.organization_members
        WHERE user_id = v_uid AND status = 'active' AND org_id <> p_org_id
      ) THEN
        RAISE EXCEPTION 'You already belong to a company. Leave it before joining another.';
      END IF;

      SELECT lower(nullif(split_part(email, '@', 2), '')) INTO v_domain
        FROM public.users WHERE id = v_uid;

      INSERT INTO public.organization_members
        (org_id, user_id, member_role, is_current, status, requested_company_name, requested_email_domain)
      VALUES
        (p_org_id, v_uid, 'broker', false, 'pending', v_name, v_domain)
      ON CONFLICT (org_id, user_id) DO UPDATE
        SET status = CASE WHEN public.organization_members.status = 'active'
                          THEN 'active' ELSE 'pending' END,
            is_current = (public.organization_members.status = 'active'),
            requested_company_name = EXCLUDED.requested_company_name,
            requested_email_domain = EXCLUDED.requested_email_domain
      RETURNING * INTO v_row;

      RETURN v_row;
    END;
    $function$;

CREATE OR REPLACE FUNCTION public.fn_rq_on_review()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status IN ('APPROVED','REJECTED') AND OLD.status = 'PENDING' THEN
    NEW.reviewed_at := NOW();

    IF NEW.listing_type = 'cargo' THEN
      UPDATE cargo_listings
      SET review_status = NEW.status::review_status_enum,
          goes_live_at  = CASE WHEN NEW.status = 'APPROVED' THEN NOW() ELSE NULL END
      WHERE id = NEW.listing_id;
    ELSIF NEW.listing_type = 'vessel_availability' THEN
      UPDATE vessel_availability
      SET review_status = NEW.status::review_status_enum,
          goes_live_at  = CASE WHEN NEW.status = 'APPROVED' THEN NOW() ELSE NULL END
      WHERE id = NEW.listing_id;
    END IF;

    -- Track clean submissions toward VERIFIED tier upgrade
    IF NEW.status = 'APPROVED' AND NEW.action_taken = 'approved' THEN
      UPDATE users
      SET clean_posts = clean_posts + 1
      WHERE id = NEW.submitted_by;
    END IF;

    -- Track strikes for amendments or flags
    IF NEW.action_taken IN ('amended','flagged') THEN
      UPDATE users
      SET strike_count = strike_count + 1
      WHERE id = NEW.submitted_by;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_search_organizations(q text)
 RETURNS TABLE(id uuid, name text, org_type text, country text, fleet_total integer)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT o.id, o.name, o.org_type, o.country, o.fleet_total
  FROM public.organizations o
  WHERE length(btrim(coalesce(q, ''))) >= 2
    AND o.name ILIKE '%' || btrim(q) || '%'
  ORDER BY o.name
  LIMIT 20;
$function$;

CREATE OR REPLACE FUNCTION public.fn_set_market_insights_narrative(p_week_id text, p_text text)
 RETURNS market_insights_editions
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_row public.market_insights_editions;
BEGIN
  UPDATE public.market_insights_editions
     SET narrative = p_text
   WHERE week_id = p_week_id
  RETURNING * INTO v_row;
  IF v_row.id IS NULL THEN RAISE EXCEPTION 'Edition % not found', p_week_id; END IF;
  RETURN v_row;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_submission_route()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  submitter_tier trust_tier_enum;
  vessel_risk    risk_level_enum;
  do_gate        BOOLEAN := FALSE;
  gate_reason    TEXT;
  is_sample      BOOLEAN := FALSE;
BEGIN
  -- Get trust tier of the posting user
  -- (posting user is tracked in listing_ownership, last inserted row)
  SELECT u.trust_tier INTO submitter_tier
  FROM listing_ownership lo
  JOIN users u ON u.id = lo.owner_user_id
  WHERE lo.listing_id   = NEW.id
    AND lo.listing_type = TG_ARGV[0]::listing_type_enum
    AND lo.is_current   = TRUE
  LIMIT 1;

  submitter_tier := COALESCE(submitter_tier, 'NEW');

  -- Always gate NEW and FLAGGED users
  IF submitter_tier IN ('NEW','FLAGGED') THEN
    do_gate     := TRUE;
    gate_reason := 'User trust tier: ' || submitter_tier;
  END IF;

  -- Always gate HIGH risk vessels regardless of tier
  IF TG_ARGV[0] = 'vessel_availability' THEN
    SELECT v.risk_level INTO vessel_risk
    FROM vessels v WHERE v.id = NEW.vessel_id;
    IF vessel_risk = 'HIGH' THEN
      do_gate     := TRUE;
      gate_reason := COALESCE(gate_reason || ' + ', '') || 'HIGH risk vessel';
    END IF;
  END IF;

  -- Random sample 1 in 10 VERIFIED posts
  IF NOT do_gate AND submitter_tier = 'VERIFIED' THEN
    IF random() < 0.1 THEN
      is_sample   := TRUE;
      do_gate     := TRUE;
      gate_reason := 'Random sample check';
    END IF;
  END IF;

  IF do_gate THEN
    INSERT INTO review_queue (
      listing_type, listing_id, submitted_by,
      trust_tier_at_submit, review_reason, is_random_sample
    )
    SELECT
      TG_ARGV[0]::listing_type_enum,
      NEW.id,
      lo.owner_user_id,
      submitter_tier,
      gate_reason,
      is_sample
    FROM listing_ownership lo
    WHERE lo.listing_id   = NEW.id
      AND lo.listing_type = TG_ARGV[0]::listing_type_enum
      AND lo.is_current   = TRUE
    LIMIT 1;
  ELSE
    -- VERIFIED user, not sampled: goes live immediately
    IF TG_ARGV[0] = 'cargo' THEN
      UPDATE cargo_listings
      SET review_status = 'APPROVED', goes_live_at = NOW()
      WHERE id = NEW.id;
    ELSE
      UPDATE vessel_availability
      SET review_status = 'APPROVED', goes_live_at = NOW()
      WHERE id = NEW.id;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_users_auto_upgrade()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.clean_posts >= 5 AND OLD.trust_tier = 'NEW' THEN
    NEW.trust_tier := 'VERIFIED';
  END IF;
  -- Auto-flag at 2 strikes
  IF NEW.strike_count >= 2 AND NEW.trust_tier = 'VERIFIED' THEN
    NEW.trust_tier := 'FLAGGED';
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_va_port_autofill()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.open_port_locode IS NOT NULL AND
     (OLD.open_port_locode IS DISTINCT FROM NEW.open_port_locode) THEN
    SELECT trade_name, zone
    INTO NEW.open_port_name, NEW.open_zone
    FROM ports WHERE locode = NEW.open_port_locode;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.fn_vessel_contact_history_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.is_current THEN
    -- Close previous current row
    UPDATE vessel_contact_history
    SET is_current = FALSE, valid_until = NOW()
    WHERE vessel_id = NEW.vessel_id
      AND is_current = TRUE
      AND id != NEW.id;

    -- Sync snapshot to vessels table
    UPDATE vessels SET
      owner_company    = NEW.owner_company,
      owner_country    = NEW.owner_country,
      owner_address    = NEW.owner_address,
      manager_company  = NEW.manager_company,
      manager_country  = NEW.manager_country,
      manager_address  = NEW.manager_address,
      pic_name         = NEW.pic_name,
      pic_role         = NEW.pic_role,
      phone            = NEW.phone,
      email_general    = NEW.email_general,
      email_chartering = NEW.email_chartering,
      risk_level       = COALESCE(NEW.risk_level, risk_level),
      risk_notes       = COALESCE(NEW.risk_notes, risk_notes),
      updated_at       = NOW()
    WHERE id = NEW.vessel_id;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_admin_ops_stats()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v jsonb;
BEGIN
  IF NOT public.fn_is_admin() THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  SELECT jsonb_build_object(
    'generated_at', now(),
    'cargo', jsonb_build_object(
      'total',          (SELECT count(*)::int FROM public.cargo_listings),
      'live',           (SELECT count(*)::int FROM public.cargo_listings
                           WHERE status IN ('IN','PARTIAL') AND review_status = 'APPROVED'),
      'pending',        (SELECT count(*)::int FROM public.cargo_listings WHERE review_status = 'PENDING'),
      'posted_7d',      (SELECT count(*)::int FROM public.cargo_listings WHERE created_at >= now() - interval '7 days'),
      'spot',           (SELECT count(*)::int FROM public.cargo_listings
                           WHERE status IN ('IN','PARTIAL') AND review_status = 'APPROVED' AND is_spot = true),
      'by_status',      (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY c DESC), '[]')
                           FROM (SELECT status::text AS label, count(*)::int c FROM public.cargo_listings GROUP BY status) s),
      'by_regime',      (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY c DESC), '[]')
                           FROM (SELECT CASE WHEN is_grain_cargo THEN 'Grain & agri'
                                             WHEN cargo_type = 'Break Bulk' THEN 'Break-bulk'
                                             ELSE 'Solid bulk cargo except grain' END AS label,
                                        count(*)::int c
                                   FROM public.cargo_listings
                                   WHERE status IN ('IN','PARTIAL') AND review_status = 'APPROVED'
                                   GROUP BY 1) r),
      'by_load_zone',   (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY c DESC), '[]')
                           FROM (SELECT COALESCE(load_zone::text, 'Unknown') AS label, count(*)::int c
                                   FROM public.cargo_listings
                                   WHERE status IN ('IN','PARTIAL') AND review_status = 'APPROVED'
                                   GROUP BY 1) z),
      'by_size_band',   (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY ord), '[]')
                           FROM (SELECT band AS label, count(*)::int c, ord FROM (
                                   SELECT CASE
                                            WHEN qty_max_mt < 10000 THEN '<10K'
                                            WHEN qty_max_mt < 20000 THEN '10-20K'
                                            WHEN qty_max_mt < 35000 THEN '20-35K'
                                            WHEN qty_max_mt < 50000 THEN '35-50K'
                                            ELSE '50K+' END AS band,
                                          CASE
                                            WHEN qty_max_mt < 10000 THEN 1
                                            WHEN qty_max_mt < 20000 THEN 2
                                            WHEN qty_max_mt < 35000 THEN 3
                                            WHEN qty_max_mt < 50000 THEN 4
                                            ELSE 5 END AS ord
                                     FROM public.cargo_listings
                                     WHERE status IN ('IN','PARTIAL') AND review_status = 'APPROVED'
                                   ) q GROUP BY band, ord) b)
    ),
    'vessels', jsonb_build_object(
      'total',          (SELECT count(*)::int FROM public.vessels),
      'sanctioned',     (SELECT count(*)::int FROM public.vessels WHERE is_sanctioned = true),
      'geared',         (SELECT count(*)::int FROM public.vessels WHERE is_geared = true),
      'open_positions', (SELECT count(*)::int FROM public.vessel_availability
                           WHERE status = 'OPEN' AND review_status = 'APPROVED'),
      'positions_pending', (SELECT count(*)::int FROM public.vessel_availability WHERE review_status = 'PENDING'),
      'posted_7d',      (SELECT count(*)::int FROM public.vessel_availability WHERE created_at >= now() - interval '7 days'),
      'by_type',        (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY c DESC), '[]')
                           FROM (SELECT COALESCE(vessel_type::text, 'Unknown') AS label, count(*)::int c
                                   FROM public.vessels GROUP BY 1) t),
      'by_open_zone',   (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY c DESC), '[]')
                           FROM (SELECT COALESCE(open_zone::text, 'Unknown') AS label, count(*)::int c
                                   FROM public.vessel_availability
                                   WHERE status = 'OPEN' AND review_status = 'APPROVED'
                                   GROUP BY 1) z),
      'by_age_band',    (SELECT COALESCE(jsonb_agg(jsonb_build_object('label', label, 'count', c) ORDER BY ord), '[]')
                           FROM (SELECT band AS label, count(*)::int c, ord FROM (
                                   SELECT CASE
                                            WHEN build_year IS NULL THEN 'Unknown'
                                            WHEN (extract(year FROM now())::int - build_year) <= 5 THEN '0-5 yrs'
                                            WHEN (extract(year FROM now())::int - build_year) <= 10 THEN '6-10 yrs'
                                            WHEN (extract(year FROM now())::int - build_year) <= 15 THEN '11-15 yrs'
                                            WHEN (extract(year FROM now())::int - build_year) <= 20 THEN '16-20 yrs'
                                            ELSE '20+ yrs' END AS band,
                                          CASE
                                            WHEN build_year IS NULL THEN 9
                                            WHEN (extract(year FROM now())::int - build_year) <= 5 THEN 1
                                            WHEN (extract(year FROM now())::int - build_year) <= 10 THEN 2
                                            WHEN (extract(year FROM now())::int - build_year) <= 15 THEN 3
                                            WHEN (extract(year FROM now())::int - build_year) <= 20 THEN 4
                                            ELSE 5 END AS ord
                                     FROM public.vessels
                                   ) q GROUP BY band, ord) b)
    )
  ) INTO v;

  RETURN v;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_latest_market_insights()
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT to_jsonb(e) - 'id'
  FROM public.market_insights_editions e
  WHERE e.published_at IS NOT NULL
  ORDER BY e.range_to DESC, e.published_at DESC
  LIMIT 1;
$function$;

CREATE OR REPLACE FUNCTION public.get_market_insights_archive()
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
           'week_id', week_id, 'range_from', range_from,
           'range_to', range_to, 'published_at', published_at
         ) ORDER BY range_to DESC), '[]'::jsonb)
  FROM public.market_insights_editions
  WHERE published_at IS NOT NULL;
$function$;

CREATE OR REPLACE FUNCTION public.get_market_insights_edition(p_week_id text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT to_jsonb(e) - 'id'
  FROM public.market_insights_editions e
  WHERE e.published_at IS NOT NULL AND e.week_id = p_week_id
  LIMIT 1;
$function$;

CREATE OR REPLACE FUNCTION public.get_matches_for_availability(p_availability_id uuid)
 RETURNS TABLE(cargo_id uuid, ref text, commodity_name text, cargo_type text, qty_min_mt integer, qty_max_mt integer, load_port_name text, load_zone text, disch_port_name text, disch_zone text, laycan_from date, laycan_to date, is_spot boolean, is_grain_cargo boolean, is_dg_cargo boolean, load_terms text, freight_idea_usd_mt numeric, requires_geared boolean, max_vessel_age_yr smallint, max_draft_m numeric, max_loa_m numeric, is_rate_aligned boolean, dwt_delta integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_va           public.vessel_availability%ROWTYPE;
  v_vessel       public.vessels%ROWTYPE;
  v_current_year integer := EXTRACT(YEAR FROM NOW())::integer;
  v_vessel_age   integer;
BEGIN
  SELECT * INTO v_va FROM public.vessel_availability WHERE id = p_availability_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Availability record not found: %', p_availability_id;
  END IF;
  SELECT * INTO v_vessel FROM public.vessels WHERE id = v_va.vessel_id AND is_sanctioned = FALSE;
  IF NOT FOUND THEN RETURN; END IF;
  v_vessel_age := v_current_year - COALESCE(v_vessel.build_year, 0);

  RETURN QUERY
  SELECT
    cl.id, cl.ref, cl.commodity_name, cl.cargo_type::text, cl.qty_min_mt, cl.qty_max_mt,
    cl.load_port_name, cl.load_zone::text, cl.disch_port_name, cl.disch_zone::text,
    cl.laycan_from, cl.laycan_to, cl.is_spot, cl.is_grain_cargo, cl.is_dg_cargo,
    cl.load_terms::text, cl.freight_idea_usd_mt, cl.requires_geared, cl.max_vessel_age_yr,
    cl.max_draft_m, cl.max_loa_m,
    (cl.freight_idea_usd_mt IS NOT NULL AND v_va.freight_idea_usd_mt IS NOT NULL
       AND ABS(cl.freight_idea_usd_mt - v_va.freight_idea_usd_mt) <= 5.0) AS is_rate_aligned,
    ABS(COALESCE(v_vessel.dwt_grain, 0) - cl.qty_max_mt) AS dwt_delta
  FROM public.cargo_listings cl
  WHERE
    cl.review_status::text = 'APPROVED'
    AND cl.status::text IN ('IN', 'PARTIAL')
    AND (v_va.open_zone::text = cl.load_zone::text OR v_va.open_zone::text = cl.disch_zone::text)
    AND v_vessel.dwt_grain IS NOT NULL
    AND (
      CASE
        WHEN v_va.accepts_part_cargo THEN
          v_vessel.dwt_grain >= cl.qty_min_mt AND v_vessel.dwt_grain <= cl.qty_max_mt * 1.20 AND v_vessel.dwt_grain >= cl.qty_max_mt * 0.80
        ELSE
          v_vessel.dwt_grain >= cl.qty_min_mt AND v_vessel.dwt_grain <= cl.qty_max_mt * 1.10 AND v_vessel.dwt_grain >= cl.qty_max_mt * 0.90
      END
    )
    AND (cl.cargo_type::text = 'Break Bulk' OR v_vessel.vessel_type::text IN ('Bulk Carrier', 'General Cargo'))
    AND (
      cl.is_spot = TRUE
      OR (v_va.open_date IS NOT NULL AND cl.laycan_from IS NOT NULL
          AND v_va.open_date BETWEEN (cl.laycan_from - INTERVAL '21 days')::date
                                  AND (cl.laycan_from + INTERVAL '14 days')::date)
    )
    AND (cl.requires_geared IS NULL OR cl.requires_geared = FALSE OR v_vessel.is_geared = TRUE)
    -- GRAIN hard-block: grain cargo → grain-certified vessel
    AND (cl.is_grain_cargo = FALSE OR COALESCE(v_vessel.grain_certified, FALSE) = TRUE)
    -- DG hard-block: DG cargo → DG-certified vessel
    AND (cl.is_dg_cargo = FALSE OR COALESCE(v_vessel.dg_certified, FALSE) = TRUE)
    AND (cl.max_vessel_age_yr IS NULL OR v_vessel.build_year IS NULL OR v_vessel_age <= cl.max_vessel_age_yr)
    AND (cl.max_draft_m IS NULL OR v_vessel.max_draft_m IS NULL OR v_vessel.max_draft_m <= cl.max_draft_m)
    AND (cl.max_loa_m IS NULL OR v_vessel.max_loa_m IS NULL OR v_vessel.max_loa_m <= cl.max_loa_m)
  ORDER BY is_rate_aligned DESC, dwt_delta ASC;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_matches_for_cargo(p_cargo_id uuid)
 RETURNS TABLE(availability_id uuid, vessel_ref text, vessel_id uuid, vessel_name text, vessel_type text, dwt_grain integer, build_year smallint, flag text, scope text, risk_level text, is_geared boolean, grain_certified boolean, dg_certified boolean, open_port_name text, open_zone text, open_date date, open_date_range_days smallint, accepts_part_cargo boolean, freight_idea_usd_mt numeric, is_rate_aligned boolean, dwt_delta integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_cl            public.cargo_listings%ROWTYPE;
  v_current_year  integer := EXTRACT(YEAR FROM NOW())::integer;
BEGIN
  SELECT * INTO v_cl FROM public.cargo_listings WHERE id = p_cargo_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Cargo listing not found: %', p_cargo_id;
  END IF;
  IF v_cl.status::text NOT IN ('IN', 'PARTIAL') OR v_cl.review_status::text != 'APPROVED' THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    -- vessel_availability has no `ref` column on this database; use the vessel's
    -- IMO number as the vessel reference (SDK treats vessel_ref as nullable text).
    va.id, v.imo_number, v.id, v.vessel_name, v.vessel_type::text, v.dwt_grain,
    v.build_year, v.flag, v.scope::text, v.risk_level::text, v.is_geared, v.grain_certified,
    v.dg_certified, va.open_port_name, va.open_zone::text, va.open_date,
    va.open_date_range_days, va.accepts_part_cargo, va.freight_idea_usd_mt,
    (v_cl.freight_idea_usd_mt IS NOT NULL AND va.freight_idea_usd_mt IS NOT NULL
       AND ABS(v_cl.freight_idea_usd_mt - va.freight_idea_usd_mt) <= 5.0) AS is_rate_aligned,
    ABS(COALESCE(v.dwt_grain, 0) - v_cl.qty_max_mt) AS dwt_delta
  FROM public.vessel_availability va
  JOIN public.vessels v ON v.id = va.vessel_id
  WHERE
    v.is_sanctioned = FALSE
    AND va.status::text = 'OPEN'
    AND va.review_status::text = 'APPROVED'
    AND (va.open_zone::text = v_cl.load_zone::text OR va.open_zone::text = v_cl.disch_zone::text)
    AND v.dwt_grain IS NOT NULL
    AND (
      CASE
        WHEN va.accepts_part_cargo THEN
          v.dwt_grain >= v_cl.qty_min_mt AND v.dwt_grain <= v_cl.qty_max_mt * 1.20 AND v.dwt_grain >= v_cl.qty_max_mt * 0.80
        ELSE
          v.dwt_grain >= v_cl.qty_min_mt AND v.dwt_grain <= v_cl.qty_max_mt * 1.10 AND v.dwt_grain >= v_cl.qty_max_mt * 0.90
      END
    )
    AND (v_cl.cargo_type::text = 'Break Bulk' OR v.vessel_type::text IN ('Bulk Carrier', 'General Cargo'))
    AND (
      v_cl.is_spot = TRUE
      OR (va.open_date IS NOT NULL AND v_cl.laycan_from IS NOT NULL
          AND va.open_date BETWEEN (v_cl.laycan_from - INTERVAL '21 days')::date
                                AND (v_cl.laycan_from + INTERVAL '14 days')::date)
    )
    AND (v_cl.requires_geared IS NULL OR v_cl.requires_geared = FALSE OR v.is_geared = TRUE)
    -- GRAIN hard-block: grain cargo → grain-certified vessel
    AND (v_cl.is_grain_cargo = FALSE OR COALESCE(v.grain_certified, FALSE) = TRUE)
    -- DG hard-block: DG cargo → DG-certified vessel
    AND (v_cl.is_dg_cargo = FALSE OR COALESCE(v.dg_certified, FALSE) = TRUE)
    AND (v_cl.max_vessel_age_yr IS NULL OR v.build_year IS NULL OR (v_current_year - v.build_year::integer) <= v_cl.max_vessel_age_yr)
    AND (v_cl.max_draft_m IS NULL OR v.max_draft_m IS NULL OR v.max_draft_m <= v_cl.max_draft_m)
    AND (v_cl.max_loa_m IS NULL OR v.max_loa_m IS NULL OR v.max_loa_m <= v_cl.max_loa_m)
  ORDER BY is_rate_aligned DESC, dwt_delta ASC;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_public_platform_totals()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_cargo int := 0; v_vessel int := 0; v_open int := 0;
  v_port int := 0; v_zone int := 0; v_company int := 0;
BEGIN
  IF to_regclass('public.cargo_listings') IS NOT NULL THEN
    SELECT count(*)::int INTO v_cargo FROM public.cargo_listings
      WHERE status IN ('IN','PARTIAL') AND review_status = 'APPROVED';
  END IF;
  IF to_regclass('public.vessels') IS NOT NULL THEN
    SELECT count(*)::int INTO v_vessel FROM public.vessels;
  END IF;
  IF to_regclass('public.vessel_availability') IS NOT NULL THEN
    SELECT count(*)::int INTO v_open FROM public.vessel_availability
      WHERE status = 'OPEN' AND review_status = 'APPROVED';
  END IF;
  IF to_regclass('public.ports') IS NOT NULL THEN
    SELECT count(*)::int INTO v_port FROM public.ports;
    SELECT count(DISTINCT zone)::int INTO v_zone FROM public.ports
      WHERE zone IS NOT NULL AND zone::text <> 'Unknown';
  END IF;
  IF to_regclass('public.organizations') IS NOT NULL THEN
    SELECT count(*)::int INTO v_company FROM public.organizations;
  END IF;

  RETURN jsonb_build_object(
    'cargo_live',     v_cargo,
    'vessels',        v_vessel,
    'open_positions', v_open,
    'ports',          v_port,
    'zones',          v_zone,
    'companies',      v_company
  );
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_public_stats()
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
WITH avail_cargo AS (
  SELECT load_zone AS zone
  FROM public.cargo_listings
  WHERE status IN ('IN','PARTIAL')
    AND review_status = 'APPROVED'
    AND (
      is_spot = TRUE
      OR (
        laycan_from <= (CURRENT_DATE + 7)
        AND COALESCE(laycan_to, laycan_from) >= (CURRENT_DATE - 7)
      )
    )
),
avail_vessel AS (
  SELECT open_zone AS zone
  FROM public.vessel_availability
  WHERE status = 'OPEN'
    AND review_status = 'APPROVED'
    AND (
      open_date IS NULL
      OR open_date BETWEEN (CURRENT_DATE - 7) AND (CURRENT_DATE + 7)
    )
)
SELECT jsonb_build_object(
  'cargo_count',  (SELECT count(*)::int FROM avail_cargo),
  'vessel_count', (SELECT count(*)::int FROM avail_vessel),
  'zone_count',   (
    SELECT count(DISTINCT zone)::int
    FROM (
      SELECT zone FROM avail_cargo
      UNION
      SELECT zone FROM avail_vessel
    ) z
    WHERE zone IS NOT NULL AND zone::text <> 'Unknown'
  )
);
$function$;

CREATE OR REPLACE FUNCTION public.is_admin()
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
        SELECT public.fn_is_admin();
      $function$;

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$;

-- ── Views ───────────────────────────────────────────────────────────
create or replace view public."v_live_cargo" as
 SELECT cl.id,
    cl.ref,
    cl.batch_id,
    cl.batch_date,
    cl.status,
    cl.priority,
    cl.cargo_group_id,
    cl.cargo_type,
    cl.commodity_id,
    cl.commodity_name,
    cl.is_dg_cargo,
    cl.is_grain_cargo,
    cl.qty_min_mt,
    cl.qty_max_mt,
    cl.stowage_factor,
    cl.load_port_locode,
    cl.load_port_name,
    cl.load_zone,
    cl.load_country,
    cl.disch_port_locode,
    cl.disch_port_name,
    cl.disch_zone,
    cl.disch_country,
    cl.laycan_from,
    cl.laycan_to,
    cl.is_spot,
    cl.load_rate,
    cl.disch_rate,
    cl.load_terms,
    cl.laytime_structure,
    cl.nor_clause,
    cl.freight_idea_usd_mt,
    cl.commission_pct,
    cl.demurrage_rate,
    cl.despatch_rate,
    cl.requires_geared,
    cl.max_vessel_age_yr,
    cl.max_loa_m,
    cl.max_draft_m,
    cl.broker,
    cl.notes,
    cl.review_status,
    cl.goes_live_at,
    cl.created_at,
    cl.updated_at,
    c.imsbc_category,
    c.is_dg,
    c.is_grain
   FROM cargo_listings cl
     JOIN commodities c ON c.id = cl.commodity_id
  WHERE cl.review_status = 'APPROVED'::review_status_enum AND (cl.status = ANY (ARRAY['IN'::cargo_status_enum, 'PARTIAL'::cargo_status_enum]));

create or replace view public."v_live_vessels" as
 SELECT va.id,
    va.vessel_id,
    va.open_port_locode,
    va.open_port_name,
    va.open_zone,
    va.open_date,
    va.open_date_range_days,
    va.last_cargo,
    va.service_speed_kn,
    va.me_consumption_mt_day,
    va.aux_consumption_mt_day,
    va.freight_idea_usd_mt,
    va.accepts_part_cargo,
    va.status,
    va.review_status,
    va.goes_live_at,
    va.notes,
    va.created_at,
    va.updated_at,
    v.vessel_type,
    v.dwt_grain,
    v.dwt_bale,
    v.is_geared,
    v.grain_certified,
    v.dg_certified,
    v.max_loa_m,
    v.max_draft_m,
    v.build_year,
    v.scope,
    v.risk_level,
    v.is_sanctioned
   FROM vessel_availability va
     JOIN vessels v ON v.id = va.vessel_id
  WHERE va.review_status = 'APPROVED'::review_status_enum AND va.status = 'OPEN'::vessel_status_enum AND v.is_sanctioned = false;

create or replace view public."v_admin_queue" as
 SELECT rq.id,
    rq.listing_type,
    rq.listing_id,
    rq.submitted_by,
    rq.trust_tier_at_submit,
    rq.review_reason,
    rq.is_random_sample,
    rq.status,
    rq.reviewed_by,
    rq.action_taken,
    rq.admin_note,
    rq.amendment_detail,
    rq.submitted_at,
    rq.reviewed_at,
    u.full_name AS submitter_name,
    u.company AS submitter_company,
    u.trust_tier
   FROM review_queue rq
     JOIN users u ON u.id = rq.submitted_by
  WHERE rq.status = 'PENDING'::review_status_enum
  ORDER BY rq.submitted_at;

create or replace view public."v_cargo_match_counts" as
 SELECT c.id AS cargo_id,
    count(m.id) AS total_matches,
    count(*) FILTER (WHERE m.score_label = 'Strong'::text) AS strong,
    count(*) FILTER (WHERE m.score_label = 'Good'::text) AS good,
    count(*) FILTER (WHERE m.score_label = 'Possible'::text) AS possible,
    count(*) FILTER (WHERE m.score_label = 'Weak'::text) AS weak
   FROM cargo_listings c
     LEFT JOIN matches m ON m.cargo_id = c.id
  WHERE c.review_status = 'APPROVED'::review_status_enum AND (c.status = ANY (ARRAY['IN'::cargo_status_enum, 'PARTIAL'::cargo_status_enum]))
  GROUP BY c.id;

create or replace view public."v_vessel_match_counts" as
 SELECT v.id AS vessel_avail_id,
    count(m.id) AS total_matches,
    count(*) FILTER (WHERE m.score_label = 'Strong'::text) AS strong,
    count(*) FILTER (WHERE m.score_label = 'Good'::text) AS good,
    count(*) FILTER (WHERE m.score_label = 'Possible'::text) AS possible,
    count(*) FILTER (WHERE m.score_label = 'Weak'::text) AS weak
   FROM vessel_availability v
     LEFT JOIN matches m ON m.vessel_avail_id = v.id
  WHERE v.review_status = 'APPROVED'::review_status_enum AND v.status = 'OPEN'::vessel_status_enum
  GROUP BY v.id;

-- ── Triggers ────────────────────────────────────────────────────────
CREATE TRIGGER trg_cargo_listings_updated_at BEFORE UPDATE ON public.cargo_listings FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();
CREATE TRIGGER trg_cargo_submission_route AFTER INSERT ON public.cargo_listings FOR EACH ROW EXECUTE FUNCTION fn_submission_route('cargo');
CREATE TRIGGER trg_cl_auto_reject_claims AFTER UPDATE ON public.cargo_listings FOR EACH ROW EXECUTE FUNCTION fn_oc_auto_reject_on_close();
