CREATE TRIGGER trg_cl_port_autofill BEFORE INSERT OR UPDATE ON public.cargo_listings FOR EACH ROW EXECUTE FUNCTION fn_cl_port_autofill();
CREATE TRIGGER trg_csa_writeback AFTER INSERT OR UPDATE ON public.cargo_safety_answers FOR EACH ROW EXECUTE FUNCTION fn_csa_matchmaking_writeback();
