CREATE TRIGGER trg_oc_detect_dispute BEFORE INSERT ON public.ownership_claims FOR EACH ROW EXECUTE FUNCTION fn_oc_detect_dispute();
CREATE TRIGGER trg_profiles_updated_at BEFORE UPDATE ON public.profiles FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();
CREATE TRIGGER trg_rq_on_review BEFORE UPDATE ON public.review_queue FOR EACH ROW EXECUTE FUNCTION fn_rq_on_review();
CREATE TRIGGER trg_safety_questions_updated_at BEFORE UPDATE ON public.safety_questions FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();
CREATE TRIGGER trg_users_auto_upgrade BEFORE UPDATE ON public.users FOR EACH ROW EXECUTE FUNCTION fn_users_auto_upgrade();
CREATE TRIGGER trg_users_updated_at BEFORE UPDATE ON public.users FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();
CREATE TRIGGER trg_va_match_cleanup AFTER UPDATE OF status, review_status ON public.vessel_availability FOR EACH ROW EXECUTE FUNCTION fn_match_auto_cleanup();
CREATE TRIGGER trg_va_port_autofill BEFORE INSERT OR UPDATE ON public.vessel_availability FOR EACH ROW EXECUTE FUNCTION fn_va_port_autofill();
