-- ── Row Level Security ──────────────────────────────────────────────
alter table public."announcements" enable row level security;
alter table public."cargo_listings" enable row level security;
alter table public."cargo_safety_answers" enable row level security;
alter table public."commodities" enable row level security;
alter table public."fuel_prices" enable row level security;
alter table public."listing_ownership" enable row level security;
alter table public."market_insights_editions" enable row level security;
alter table public."market_insights_subscribers" enable row level security;
alter table public."matches" enable row level security;
alter table public."organization_members" enable row level security;
alter table public."organizations" enable row level security;
alter table public."ownership_claims" enable row level security;
alter table public."ports" enable row level security;
alter table public."profiles" enable row level security;
alter table public."review_queue" enable row level security;
alter table public."safety_questions" enable row level security;
alter table public."users" enable row level security;
alter table public."vessel_availability" enable row level security;
