-- ── Policies ────────────────────────────────────────────────────────
create policy "ann: admin all" on public."announcements" as permissive for all to public
  using (fn_is_admin());
create policy "ann: auth read active" on public."announcements" as permissive for select to public
  using (((active = true) AND ((expires_at IS NULL) OR (expires_at > now()))));
create policy "cl: admin all" on public."cargo_listings" as permissive for all to public
  using (fn_is_admin());
create policy "cl: auth see live" on public."cargo_listings" as permissive for select to public
  using (((auth.role() = 'authenticated'::text) AND (review_status = 'APPROVED'::review_status_enum) AND (status = ANY (ARRAY['IN'::cargo_status_enum, 'PARTIAL'::cargo_status_enum]))));
create policy "cl: owner insert" on public."cargo_listings" as permissive for insert to public
  with check ((auth.role() = 'authenticated'::text));
create policy "cl: owner see own" on public."cargo_listings" as permissive for select to public
  using ((EXISTS ( SELECT 1
   FROM listing_ownership lo
  WHERE ((lo.listing_id = cargo_listings.id) AND (lo.listing_type = 'cargo'::listing_type_enum) AND (lo.owner_user_id = auth.uid())))));
create policy "cl: owner update own" on public."cargo_listings" as permissive for update to public
  using ((EXISTS ( SELECT 1
   FROM listing_ownership lo
  WHERE ((lo.listing_id = cargo_listings.id) AND (lo.listing_type = 'cargo'::listing_type_enum) AND (lo.owner_user_id = auth.uid()) AND (lo.role = 'primary'::ownership_role_enum) AND (lo.is_current = true)))));
create policy "csa: admin all" on public."cargo_safety_answers" as permissive for all to public
  using (fn_is_admin());
create policy "csa: owner see own" on public."cargo_safety_answers" as permissive for select to public
  using ((EXISTS ( SELECT 1
   FROM listing_ownership lo
  WHERE ((lo.listing_id = cargo_safety_answers.cargo_listing_id) AND (lo.listing_type = 'cargo'::listing_type_enum) AND (lo.owner_user_id = auth.uid())))));
create policy "csa: owner write own" on public."cargo_safety_answers" as permissive for insert to public
  with check ((EXISTS ( SELECT 1
   FROM listing_ownership lo
  WHERE ((lo.listing_id = cargo_safety_answers.cargo_listing_id) AND (lo.listing_type = 'cargo'::listing_type_enum) AND (lo.owner_user_id = auth.uid()) AND (lo.role = 'primary'::ownership_role_enum)))));
create policy "commodities: admin all" on public."commodities" as permissive for all to public
  using (fn_is_admin());
create policy "commodities: all read active" on public."commodities" as permissive for select to public
  using ((is_active = true));
create policy "fuel_prices: admin all" on public."fuel_prices" as permissive for all to public
  using (fn_is_admin());
create policy "fuel_prices: all read active" on public."fuel_prices" as permissive for select to public
  using ((is_active = true));
create policy "lo: admin all" on public."listing_ownership" as permissive for all to public
  using (fn_is_admin());
create policy "lo: own rows only" on public."listing_ownership" as permissive for select to public
  using ((owner_user_id = auth.uid()));
create policy "insights: admin all" on public."market_insights_editions" as permissive for all to authenticated
  using (fn_is_admin())
  with check (fn_is_admin());
create policy "insights: read published" on public."market_insights_editions" as permissive for select to anon, authenticated
  using ((published_at IS NOT NULL));
create policy "insights subs: admin read" on public."market_insights_subscribers" as permissive for all to authenticated
  using (fn_is_admin())
  with check (fn_is_admin());
create policy "matches: admin all" on public."matches" as permissive for all to public
  using (fn_is_admin());
create policy "matches: auth read" on public."matches" as permissive for select to public
  using ((auth.role() = 'authenticated'::text));
create policy "members managed by org admin" on public."organization_members" as permissive for all to authenticated
  using ((fn_is_admin() OR (EXISTS ( SELECT 1
   FROM organization_members m
  WHERE ((m.org_id = organization_members.org_id) AND (m.user_id = fn_app_user_id()) AND (m.member_role = 'admin'::text) AND m.is_current)))))
  with check ((fn_is_admin() OR (EXISTS ( SELECT 1
   FROM organization_members m
  WHERE ((m.org_id = organization_members.org_id) AND (m.user_id = fn_app_user_id()) AND (m.member_role = 'admin'::text) AND m.is_current)))));
create policy "members read own org" on public."organization_members" as permissive for select to authenticated
  using ((fn_is_admin() OR (org_id = ANY (fn_my_org_ids()))));
create policy "orgs admin writes" on public."organizations" as permissive for all to authenticated
  using (fn_is_admin())
  with check (fn_is_admin());
create policy "orgs readable to own members" on public."organizations" as permissive for select to authenticated
  using ((fn_is_admin() OR (id = ANY (fn_my_org_ids()))));
create policy "oc: admin all" on public."ownership_claims" as permissive for all to public
  using (fn_is_admin());
create policy "oc: insert own" on public."ownership_claims" as permissive for insert to public
  with check (((auth.role() = 'authenticated'::text) AND (claimant_user_id = auth.uid())));
create policy "oc: own claims" on public."ownership_claims" as permissive for select to public
  using ((claimant_user_id = auth.uid()));
create policy "ports: admin all" on public."ports" as permissive for all to public
  using (fn_is_admin());
create policy "ports: all read verified" on public."ports" as permissive for select to public
  using ((is_verified = true));
create policy "Admins manage profiles" on public."profiles" as permissive for all to authenticated
  using (fn_is_admin())
  with check (fn_is_admin());
create policy "Users insert own profiles" on public."profiles" as permissive for insert to authenticated
  with check ((account_id = fn_app_user_id()));
create policy "Users read own profiles" on public."profiles" as permissive for select to authenticated
  using ((account_id = fn_app_user_id()));
create policy "Users update own profiles" on public."profiles" as permissive for update to authenticated
  using ((account_id = fn_app_user_id()));
create policy "rq: admin all" on public."review_queue" as permissive for all to public
  using (fn_is_admin());
create policy "rq: own status" on public."review_queue" as permissive for select to public
  using ((submitted_by = auth.uid()));
create policy "sq: admin all" on public."safety_questions" as permissive for all to public
  using (fn_is_admin());
create policy "sq: all read active" on public."safety_questions" as permissive for select to public
  using ((is_active = true));
create policy "users: admin all" on public."users" as permissive for all to public
  using (fn_is_admin());
create policy "users: own row" on public."users" as permissive for all to public
  using ((id = auth.uid()));
create policy "va: admin all" on public."vessel_availability" as permissive for all to public
  using (fn_is_admin());
create policy "va: auth see live" on public."vessel_availability" as permissive for select to public
  using (((auth.role() = 'authenticated'::text) AND (review_status = 'APPROVED'::review_status_enum) AND (status = 'OPEN'::vessel_status_enum)));
create policy "va: owner insert" on public."vessel_availability" as permissive for insert to public
  with check ((auth.role() = 'authenticated'::text));
create policy "va: owner see own" on public."vessel_availability" as permissive for select to public
  using ((EXISTS ( SELECT 1
   FROM listing_ownership lo
  WHERE ((lo.listing_id = vessel_availability.id) AND (lo.listing_type = 'vessel_availability'::listing_type_enum) AND (lo.owner_user_id = auth.uid())))));
create policy "va: owner update own" on public."vessel_availability" as permissive for update to public
  using ((EXISTS ( SELECT 1
   FROM listing_ownership lo
  WHERE ((lo.listing_id = vessel_availability.id) AND (lo.listing_type = 'vessel_availability'::listing_type_enum) AND (lo.owner_user_id = auth.uid()) AND (lo.role = 'primary'::ownership_role_enum) AND (lo.is_current = true)))));
create policy "vch: admin all" on public."vessel_contact_history" as permissive for all to public
  using (fn_is_admin());
create policy "vch: auth current only" on public."vessel_contact_history" as permissive for select to public
  using (((auth.role() = 'authenticated'::text) AND (is_current = true)));
create policy "vessels: admin all" on public."vessels" as permissive for all to public
  using (fn_is_admin());
create policy "vessels: auth read non-sanctioned" on public."vessels" as permissive for select to public
  using (((auth.role() = 'authenticated'::text) AND (is_sanctioned = false)));
create policy "ve: admin all" on public."voyage_estimates" as permissive for all to public
  using (fn_is_admin());
create policy "ve: owner insert" on public."voyage_estimates" as permissive for insert to public
  with check ((auth.role() = 'authenticated'::text));
create policy "ve: owner see own" on public."voyage_estimates" as permissive for select to public
  using ((created_by = auth.uid()));

